const normalize = (v) => String(v || '').replace(/\D/g, '');
const expand = (raw) => {
  const digits = normalize(raw);
  const set = new Set();
  const add = (x) => { const d = normalize(x); if (d) set.add(d); };
  add(digits);
  const no55 = digits.startsWith('55') ? digits.slice(2) : digits;
  add(no55);
  if (no55.length === 10) {
    const with9 = no55.slice(0, 2) + '9' + no55.slice(2);
    add(with9); add('55' + with9);
  }
  if (no55.length === 11 && no55[2] === '9') {
    const without9 = no55.slice(0, 2) + no55.slice(3);
    add(without9); add('55' + without9);
  }
  return set;
};
const intersects = (a, b) => { for (const v of a) if (b.has(v)) return true; return false; };
const leadSet = expand($('Normalize Input1').first().json.lead_phone);
const rows = $input.all().map(i => i.json).filter(r => r && r.id);
const uniq = []; const seen = new Set();
for (const r of rows) { if (seen.has(r.id)) continue; seen.add(r.id); uniq.push(r); }
const score = (r) => {
  if (intersects(leadSet, expand(r.alertPhone))) return 3;
  if (intersects(leadSet, expand(r.adminPhone))) return 2;
  if (intersects(leadSet, expand(r.phone))) return 1;
  return 0;
};
const ranked = uniq.map(r => ({ r, s: score(r) })).filter(x => x.s > 0).sort((a,b) => b.s - a.s);
const best = ranked.length ? ranked[0].r : null;
let role = 'unknown';
if (best) {
  if (intersects(leadSet, expand(best.alertPhone))) role = 'alert';
  else if (intersects(leadSet, expand(best.adminPhone))) role = 'admin';
}
const matchedName = best ? (role === 'alert' ? String(best.alertContactName || best.adminName || '').trim() : role === 'admin' ? String(best.adminName || best.alertContactName || '').trim() : '') : '';
return [{ json: { is_client: !!best, client_id: best?.id || null, client_match: best, matched_contact_role: role, matched_contact_name: matchedName } }];

