const input = $('Set Agent Input1').first().json;
const raw = $json || {};

let normalized = raw;

if (typeof raw.output === 'object' && raw.output !== null) {
  normalized = raw.output;
} else if (typeof raw.output === 'string') {
  const text = raw.output.trim();

  if (text.startsWith('{') && text.endsWith('}')) {
    try {
      normalized = JSON.parse(text);
    } catch {
      normalized = { assistant_reply: text };
    }
  } else {
    normalized = { assistant_reply: text };
  }
} else if (typeof raw.text === 'string') {
  const text = raw.text.trim();

  if (text.startsWith('{') && text.endsWith('}')) {
    try {
      normalized = JSON.parse(text);
    } catch {
      normalized = { assistant_reply: text };
    }
  } else {
    normalized = { assistant_reply: text };
  }
}

const assistantReply = String(
  normalized.assistant_reply ||
  normalized.reply ||
  normalized.output ||
  normalized.text ||
  normalized.response ||
  ''
).trim();

const finalReply = assistantReply || 'Olá! Como posso ajudar você hoje?';

const needFollowup = Boolean(normalized.need_followup || false);
const needHandoff = Boolean(normalized.need_handoff || false);
const reason = String(normalized.reason || '').trim();

return {
  lead_phone: input.lead_phone,
  lead_name: input.lead_name,
  assistant_reply: finalReply,
  need_followup: needFollowup,
  need_handoff: needHandoff,
  reason,
  dynamic_delay_seconds: Math.max(3, Math.min(10, Math.ceil(finalReply.length / 60)))
};

